const initialFormData = {
  title: "",
  description: "",
  priority: "medium",
  deadline: "",
  projectId: id || "",
  assignedTo: "",
  createdBy: currentUser?._id || "",
};

  const [tasks, setTasks] = useState([]);
  const [projectMembers, setProjectMembers] = useState([]);
  const [formData, setFormData] = useState(initialFormData);
  const [editingTaskId, setEditingTaskId] = useState(null);
  const [commentInputs, setCommentInputs] = useState({});
  const [selectedFiles, setSelectedFiles] = useState({});
  const [showForm, setShowForm] = useState(false);
  

  const fetchTasks = async () => {
    try {
      if (!id) return;
      const data = await getTasksByProject(id);
      setTasks(data);
    } catch (error) {
      /* eslint-disable */console.error(...oo_tx(`3999337597_46_6_46_59_11`,"Error fetching tasks:", error.message));
    }
  };

  const fetchProjectMembers = async () => {
    try {
      if (!id) return;
      const project = await getProjectById(id);
      setProjectMembers(project.members || []);
    } catch (error) {
      /* eslint-disable */console.error(...oo_tx(`3999337597_56_6_56_69_11`,"Error fetching project members:", error.message));
    }
  };

  useEffect(() => {
    setFormData((prev) => ({
      ...prev,
      projectId: id || "",
    }));

    fetchTasks();
    fetchProjectMembers();
  }, [id]);

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

const handleSubmit = async (e) => {
  e.preventDefault();

  try {
    const payload = {
      title: formData.title,
      description: formData.description,
      priority: formData.priority,
      deadline: formData.deadline,
      projectId: id || "",
      assignedTo: formData.assignedTo,
      ...(currentUser?._id ? { createdBy: currentUser._id } : {}),
    };

    /* eslint-disable */console.log(...oo_oo(`3999337597_91_4_91_36_4`,"PAYLOAD:", payload));

    if (editingTaskId) {
      await updateTask(editingTaskId, payload);
      setEditingTaskId(null);
    } else {
      await createTask(payload);
    }

    setFormData({
      title: "",
      description: "",
      priority: "medium",
      deadline: "",
      projectId: id || "",
      assignedTo: "",
      createdBy: currentUser?._id || "",
    });

    setShowForm(false);
    fetchTasks();
  } catch (error) {
    /* eslint-disable */console.error(...oo_tx(`3999337597_113_4_113_78_11`,"Error saving task:", error.response?.data || error.message));
  }
};

  const handleDelete = async (taskId) => {
    try {
      await deleteTask(taskId);
      fetchTasks();
    } catch (error) {
      /* eslint-disable */console.error(...oo_tx(`3999337597_122_6_122_58_11`,"Error deleting task:", error.message));
    }
  };

  const handleStatusChange = async (taskId, newStatus) => {
    try {
      await updateTaskStatus(taskId, newStatus);
      fetchTasks();
    } catch (error) {
      /* eslint-disable */console.error(...oo_tx(`3999337597_131_6_131_60_11`,"Error updating status:", error.message));
    }
  };

  const handleAssignChange = async (taskId, newAssignedTo) => {
    try {
      await assignTaskToUser(taskId, newAssignedTo);
      fetchTasks();
    } catch (error) {
      /* eslint-disable */console.error(...oo_tx(`3999337597_140_6_140_59_11`,"Error assigning task:", error.message));
    }
  };

  const handleEdit = (task) => {
    setEditingTaskId(task._id);
    setShowForm(true);
    setFormData({
      title: task.title || "",
      description: task.description || "",
      priority: task.priority || "medium",
      deadline: task.deadline ? task.deadline.slice(0, 10) : "",
      projectId: task.projectId || id || "",
      assignedTo: task.assignedTo || "",
      createdBy: task.createdBy || currentUser?._id || "",
    });
  };

  const handleCancelEdit = () => {
    setEditingTaskId(null);
    setShowForm(false);
    setFormData({
      ...initialFormData,
      projectId: id || "",
    });
  };

  const handleCommentInputChange = (taskId, value) => {
    setCommentInputs((prev) => ({
      ...prev,
      [taskId]: value,
    }));
  };

  const handleAddComment = async (taskId) => {
    try {
      const text = commentInputs[taskId];

      if (!text || !text.trim()) return;
      if (!currentUser?._id) return;

      await addCommentToTask(taskId, {
        text,
        author: currentUser._id,
        authorName: currentUser.username,
      });

      setCommentInputs((prev) => ({
        ...prev,
        [taskId]: "",
      }));

      fetchTasks();
    } catch (error) {
      /* eslint-disable */console.error(...oo_tx(`3999337597_194_6_194_59_11`,"Error adding comment:", error.message));
    }
  };

  const handleFileChange = (taskId, file) => {
    setSelectedFiles((prev) => ({
      ...prev,
      [taskId]: file,
    }));
  };

  const handleFileUpload = async (taskId) => {
    try {
      const file = selectedFiles[taskId];

      if (!file) return;

      await uploadTaskFile(taskId, file);

      setSelectedFiles((prev) => ({
        ...prev,
        [taskId]: null,
      }));

      fetchTasks();
    } catch (error) {
      /* eslint-disable */console.error(...oo_tx(`3999337597_220_6_220_59_11`,"Error uploading file:", error.message));
    }
  };

  const getDeadlineStatus = (deadline) => {
    if (!deadline) return null;

    const today = new Date();
    const dueDate = new Date(deadline);

    today.setHours(0, 0, 0, 0);
    dueDate.setHours(0, 0, 0, 0);

    const diffTime = dueDate - today;
    const diffDays = diffTime / (1000 * 60 * 60 * 24);

    if (diffDays < 0) {
      return "overdue";
    }

    if (diffDays <= 2) {
      return "near";
    }

    return "normal";
  };

  const renderDeadlineReminder = (task) => {
    if (task.status === "done") return null;

    const status = getDeadlineStatus(task.deadline);

    if (!status || status === "normal") return null;

    if (status === "overdue") {
      return (
        <p className="task-deadline-alert task-deadline-alert-overdue">
          Deadline dépassée
        </p>
      );
    }

    if (status === "near") {
      return (
        <p className="task-deadline-alert task-deadline-alert-near">
          Deadline proche
        </p>
      );
    }

    return null;
  };

  return (
    <div className="task-page">
      <div className="task-page-header">
        <h1 className="task-page-title">Task Management</h1>
        <p className="task-page-subtitle">
          Créez, modifiez et suivez vos tâches dans une interface claire et moderne.
        </p>
      </div>

      <div className="task-list-header">
  <h2 className="task-section-title">Task List</h2>
  <div className="task-form-actions">
    <span className="task-list-badge">{tasks.length} tasks</span>

